import{_ as t,C as n,o,c as s,a1 as r,E as p}from"./chunks/framework.hVCBBfmZ.js";const u=JSON.parse('{"title":"大觉寺三峰大环线徒步","description":"","frontmatter":{"title":"大觉寺三峰大环线徒步","date":"2024-06-13T02:01:23.000Z","recommend":true},"headers":[],"relativePath":"posts/sanfeng.md","filePath":"posts/sanfeng.md"}'),l={name:"posts/sanfeng.md"};function i(_,e,c,d,m,f){const a=n("ImageGallery");return o(),s("div",null,[e[0]||(e[0]=r('<p>北京的三峰环线是北京越野跑和徒步爱好者的经典路线，是以大觉寺商店作为起终点，串联萝芭地北尖、阳台山、妙峰山的环形路线，全线大概 22 公里，海拔提升约 1800 米。开车的话可以导航大觉寺一号停车场，停车费 20 元一天，路途大部分时候没有信号，可以在“两步路app”提前下载好路线。</p><h2 id="装备" tabindex="-1">装备 <a class="header-anchor" href="#装备" aria-label="Permalink to &quot;装备&quot;">​</a></h2><p>腰包、充电宝、髌骨带、耳机、两瓶水、小零食、纸</p><p>再精简一些的话，可以不带充电宝和零食，水只带一瓶，然后在“妙儿洼茶棚”和“涧沟村”补给</p><h2 id="路线" tabindex="-1">路线 <a class="header-anchor" href="#路线" aria-label="Permalink to &quot;路线&quot;">​</a></h2><p>大觉寺商店 - 萝芭地北尖 - 妙儿洼茶棚 - 阳台山山顶 - 三界碑 - 妙峰山山顶 - 涧沟村 - 大觉寺商店</p><ul><li><p>6:50 从大觉寺商店出发，这里到萝芭地北尖大概五公里，连续爬升近千米，是全程最难的一段路，坡很陡，一上来小腿就似乎要抽筋，没走多远衣服就湿透了，由于前一天下雨，在山顶看到了云海，过了北尖不远就是妙儿洼茶棚，这是第一个补给站，吃喝都有，从这里继续 200 米爬升到阳台山山顶，再走十分钟到达三界碑，这里是门头沟、海淀和昌平交界，然后继续 300 米爬升到达妙峰山顶后便开始一路下坡</p></li><li><p>10:50 到达涧沟村，买了个西红柿，补充一瓶水后继续出发，出村子的路会有大概 200 米爬升，然后就几乎全是平路和下坡了</p></li><li><p>12:50 回到大觉寺商店，第一次徒步三峰用了整六小时，全程没停下来休息，下坡怕摔，也没敢太快，在山里有一小段路尝试了下越野跑，腰疼后便放弃了，这次虽然没有刻意追求时间，但还是想着尽量能赶上下午三点的篮球场，本来是给了自己 7.5 小时预算，结果超出预期，留出了回家吃饭的时间，从停车场开车半小时到家，下碗方便面，收拾好打球装备后赶往下一场...</p></li></ul><p>休息一天后带孩子走了三峰小环线，用时 8.5 小时，路上没有补给，两个人 7 瓶水，勉强支撑到下山，因为怕渴途中也没敢吃东西...</p>',8)),p(a,{dir:"/images/sanfeng/"})])}const g=t(l,[["render",i]]);export{u as __pageData,g as default};
